import math

def fractal_dimension(rules, start):
    reachable = set()
    stack = [start]
    while stack:
        name = stack.pop()
        if name in reachable:
            continue
        reachable.add(name)
        for _, ref in rules[name]:
            if ref not in reachable:
                stack.append(ref)

    rule_names = sorted(reachable)
    n = len(rule_names)
    idx = {name: i for i, name in enumerate(rule_names)}

    def build_matrix(D):
        M = [[0.0] * n for _ in range(n)]
        for name in rule_names:
            i = idx[name]
            for scale, ref in rules[name]:
                j = idx[ref]
                M[i][j] += scale ** D
        return M

    def spectral_radius(M):
        if n == 1:
            return M[0][0]
        v = [1.0] * n
        log_scale = 0.0
        K = 200
        for _ in range(K):
            w = [0.0] * n
            for i in range(n):
                s = 0.0
                for j in range(n):
                    s += M[i][j] * v[j]
                w[i] = s
            norm = max(abs(x) for x in w)
            if norm < 1e-300:
                return 0.0
            log_scale += math.log(norm)
            v = [x / norm for x in w]
        return math.exp(log_scale / K)

    lo, hi = 0.0, 30.0
    for _ in range(100):
        mid = (lo + hi) / 2.0
        sr = spectral_radius(build_matrix(mid))
        if sr > 1.0:
            lo = mid
        else:
            hi = mid

    return round((lo + hi) / 2.0, 6)

