import unittest
import math

class TestFractalDimension(unittest.TestCase):

    def test_sierpinski_triangle(self):
        rules = {"S": [(0.5, "S"), (0.5, "S"), (0.5, "S")]}
        result = fractal_dimension(rules, "S")
        expected = round(math.log(3) / math.log(2), 6)
        self.assertAlmostEqual(result, expected, places=5)

    def test_koch_curve(self):
        rules = {"K": [(1/3, "K"), (1/3, "K"), (1/3, "K"), (1/3, "K")]}
        result = fractal_dimension(rules, "K")
        expected = round(math.log(4) / math.log(3), 6)
        self.assertAlmostEqual(result, expected, places=5)

    def test_cantor_set(self):
        rules = {"C": [(1/3, "C"), (1/3, "C")]}
        result = fractal_dimension(rules, "C")
        expected = round(math.log(2) / math.log(3), 6)
        self.assertAlmostEqual(result, expected, places=5)

    def test_hidden_line_dimension_one(self):
        rules = {"L": [(0.5, "L"), (0.5, "L")]}
        result = fractal_dimension(rules, "L")
        self.assertAlmostEqual(result, 1.0, places=5)

    def test_hidden_square_dimension_two(self):
        rules = {"Q": [(0.5, "Q")] * 4}
        result = fractal_dimension(rules, "Q")
        self.assertAlmostEqual(result, 2.0, places=5)

    def test_hidden_menger_sponge(self):
        rules = {"M": [(1/3, "M")] * 20}
        result = fractal_dimension(rules, "M")
        expected = round(math.log(20) / math.log(3), 6)
        self.assertAlmostEqual(result, expected, places=5)

    def test_hidden_non_uniform_scales(self):
        rules = {"F": [(1/3, "F"), (1/3, "F"), (1/3, "F"), (2/3, "F")]}
        D = fractal_dimension(rules, "F")
        val = 3 * (1/3)**D + (2/3)**D
        self.assertAlmostEqual(val, 1.0, places=4)
        self.assertAlmostEqual(D, 1.6524, places=3)

    def test_hidden_mutual_recursion(self):
        rules = {
            "A": [(0.25, "B"), (0.25, "B")],
            "B": [(1/3, "A"), (1/3, "A")]
        }
        result = fractal_dimension(rules, "A")
        expected = 2 * math.log(2) / math.log(12)
        self.assertAlmostEqual(result, expected, places=4)

    def test_hidden_three_way_cycle(self):
        rules = {
            "A": [(0.5, "B")],
            "B": [(1/3, "C")],
            "C": [(0.25, "A"), (0.25, "A")]
        }
        result = fractal_dimension(rules, "A")
        expected = math.log(2) / math.log(24)
        self.assertAlmostEqual(result, expected, places=4)

if __name__ == '__main__':
    unittest.main()
